1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Conway's Game of Life", () => {
5	  it("should return an empty array when given an empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent live cells (both have only 1 neighbor)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a live cell alive when it has 2 or 3 live neighbors (survival)", () => {
15	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
16	    expect(result).toContainEqual([1, 0]);
17	  });
18	  it("should kill the center cell of a 3x3 block (overpopulation)", () => {
19	    const result = nextGeneration([[0, 0], [1, 0], [2, 0], [1, 1], [0, 2], [1, 2], [2, 2]]);
20	    expect(result).not.toContainEqual([1, 1]);
21	  });
22	  it.todo("should bring a dead cell to life when it has exactly 3 live neighbors (reproduction)");
23	  it.todo("should oscillate a vertical blinker into a horizontal blinker");
24	  it.todo("should keep a 2x2 block unchanged (still life)");
25	  it.todo("should handle cells with negative coordinates");
26	});
27

1	export type Cell = [number, number];
2	
3	const countLiveNeighbors = (cell: Cell, cells: Cell[]): number => {
4	  const [x, y] = cell;
5	  return cells.filter(([nx, ny]) =>
6	    !(nx === x && ny === y) &&
7	    Math.abs(nx - x) <= 1 &&
8	    Math.abs(ny - y) <= 1
9	  ).length;
10	};
11	
12	export function nextGeneration(cells: Cell[]): Cell[] {
13	  return cells.filter((cell) => {
14	    const liveNeighbors = countLiveNeighbors(cell, cells);
15	    return liveNeighbors === 2 || liveNeighbors === 3;
16	  });
17	}
